import { mkdirSync, readdirSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import { dirname, join, relative } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = dirname(dirname(fileURLToPath(import.meta.url)));
const docsRoot = join(repoRoot, "docs");
const referenceRoot = join(docsRoot, "reference");
const apiDocsRoot = join(referenceRoot, "api");
const apiReportsRoot = join(repoRoot, "api-reports");
const repoUrl = "https://github.com/jskits/loggerjs";

const generatedNotice =
  "<!-- Generated by scripts/generate-site-docs.mjs. Do not edit directly. -->";

const packageOrder = [
  "core",
  "browser",
  "node",
  "pretty",
  "processors",
  "codecs",
  "otel",
  "sentry",
  "datadog",
  "elastic",
  "loki",
  "cloudwatch",
  "database",
];

const exampleDescriptions = new Map([
  [
    "browser-basic",
    "Browser HTTP transport, offline queue, lifecycle capture, and browser integrations.",
  ],
  ["node-basic", "Node stdout transport, process capture, typed events, and redaction."],
  ["otel-basic", "OTLP JSON transport and OpenTelemetry trace context mapping."],
  ["sentry-basic", "Sentry adapter transport with structured logs, breadcrumbs, and errors."],
  ["pretty-output", "Browser and terminal pretty output demos for local developer experience."],
]);

function readJson(path) {
  return JSON.parse(readFileSync(path, "utf8"));
}

function writeFileIfChanged(path, contents) {
  const normalized = `${contents.trimEnd()}\n`;
  try {
    if (readFileSync(path, "utf8") === normalized) return;
  } catch {
    mkdirSync(dirname(path), { recursive: true });
  }
  writeFileSync(path, normalized);
}

function packageSlug(packageName) {
  return packageName.replace("@loggerjs/", "");
}

function titleFromSlug(slug) {
  return slug
    .split("-")
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function sourceFileLink(path) {
  return `${repoUrl}/blob/main/${path}`;
}

function sourceDirectoryLink(path) {
  return `${repoUrl}/tree/main/${path}`;
}

function packageMetadata() {
  const packages = readdirSync(join(repoRoot, "packages"), { withFileTypes: true })
    .filter((entry) => entry.isDirectory())
    .map((entry) => {
      const packagePath = join(repoRoot, "packages", entry.name, "package.json");
      const json = readJson(packagePath);
      return {
        dir: `packages/${entry.name}`,
        slug: packageSlug(json.name),
        name: json.name,
        version: json.version,
        description: json.description ?? "",
        exports: Object.keys(json.exports ?? {}),
        dependencies: Object.keys(json.dependencies ?? {}),
      };
    });

  return packages.toSorted(
    (left, right) => packageOrder.indexOf(left.slug) - packageOrder.indexOf(right.slug),
  );
}

function apiReports() {
  return readdirSync(apiReportsRoot, { withFileTypes: true })
    .filter((entry) => entry.isFile() && entry.name.endsWith(".api.md"))
    .map((entry) => {
      const slug = entry.name.replace(/^loggerjs-/, "").replace(/\.api\.md$/, "");
      return {
        file: entry.name,
        slug,
        packageName: `@loggerjs/${slug}`,
        title: `@loggerjs/${slug}`,
      };
    })
    .toSorted((left, right) => packageOrder.indexOf(left.slug) - packageOrder.indexOf(right.slug));
}

function examples() {
  return readdirSync(join(repoRoot, "examples"), { withFileTypes: true })
    .filter((entry) => entry.isDirectory())
    .map((entry) => {
      const dir = `examples/${entry.name}`;
      const packagePath = join(repoRoot, dir, "package.json");
      let scripts = [];
      let dependencies = [];
      try {
        const json = readJson(packagePath);
        scripts = Object.keys(json.scripts ?? {});
        dependencies = Object.keys(json.dependencies ?? {});
      } catch {
        // Some examples are plain file demos without package metadata.
      }
      return {
        slug: entry.name,
        title: titleFromSlug(entry.name),
        dir,
        description: exampleDescriptions.get(entry.name) ?? "Runnable LoggerJS example.",
        scripts,
        dependencies,
      };
    })
    .toSorted((left, right) => left.slug.localeCompare(right.slug));
}

function formatList(values) {
  if (values.length === 0) return "None";
  return values.map((value) => `\`${value}\``).join(", ");
}

function yamlString(value) {
  return JSON.stringify(value);
}

function generateReferenceIndex() {
  writeFileIfChanged(
    join(referenceRoot, "index.md"),
    `---
title: ${yamlString("Reference")}
description: ${yamlString("Generated LoggerJS package, API, and example reference index.")}
---
${generatedNotice}

# Reference

This section is generated from package metadata, checked-in API reports, and example folders in the repository.

## Generated References

- [Packages](/reference/packages): package descriptions, exports, dependencies, and source links.
- [API Reports](/reference/api/): public declaration reports generated from \`packages/*/dist/**/*.d.ts\`.
- [Examples](/examples): runnable examples and their package dependencies.

## Source Material

- [Repository README](${sourceFileLink("README.md")})
- [API reports](${sourceDirectoryLink("api-reports")})
- [Package folders](${sourceDirectoryLink("packages")})
- [Examples](${sourceDirectoryLink("examples")})
`,
  );
}

function generatePackagesPage(packages) {
  const rows = packages
    .map(
      (pkg) =>
        `| [\`${pkg.name}\`](${sourceDirectoryLink(pkg.dir)}) | ${pkg.description} | ${pkg.exports.length} | ${formatList(pkg.dependencies)} |`,
    )
    .join("\n");

  const sections = packages
    .map(
      (pkg) => `## ${pkg.name}

${pkg.description}

- Version: \`${pkg.version}\`
- Source: [${pkg.dir}](${sourceDirectoryLink(pkg.dir)})
- README: [${pkg.dir}/README.md](${sourceFileLink(`${pkg.dir}/README.md`)})
- API report: [${pkg.name}](/reference/api/${pkg.slug})
- Export subpaths: ${formatList(pkg.exports)}
- Runtime dependencies: ${formatList(pkg.dependencies)}
`,
    )
    .join("\n");

  writeFileIfChanged(
    join(referenceRoot, "packages.md"),
    `---
title: ${yamlString("Packages")}
description: ${yamlString("Generated package reference for all LoggerJS workspace packages.")}
---
${generatedNotice}

# Packages

LoggerJS is published as small packages around a dependency-free core. Platform packages re-export \`@loggerjs/core\` and add runtime-specific transports and integrations.

| Package | Description | Export subpaths | Runtime dependencies |
| --- | --- | ---: | --- |
${rows}

${sections}
`,
  );
}

function generateApiPages(reports) {
  rmSync(apiDocsRoot, { recursive: true, force: true });
  mkdirSync(apiDocsRoot, { recursive: true });

  const rows = reports
    .map(
      (report) =>
        `| [\`${report.packageName}\`](/reference/api/${report.slug}) | [api-reports/${report.file}](${sourceFileLink(`api-reports/${report.file}`)}) |`,
    )
    .join("\n");

  writeFileIfChanged(
    join(apiDocsRoot, "index.md"),
    `---
title: ${yamlString("API Reports")}
description: ${yamlString("Generated public API declaration reports for LoggerJS packages.")}
---
${generatedNotice}

# API Reports

These pages mirror the checked-in API reports produced by \`pnpm build && pnpm api:report\`.

| Package | Source report |
| --- | --- |
${rows}
`,
  );

  for (const report of reports) {
    const source = readFileSync(join(apiReportsRoot, report.file), "utf8")
      .replace(`# API Report: ${report.packageName}`, `# ${report.packageName} API`)
      .replace(
        "Update with `pnpm build && pnpm api:report` after intentional public API changes.",
        `Source report: [api-reports/${report.file}](${sourceFileLink(`api-reports/${report.file}`)}).`,
      );

    writeFileIfChanged(
      join(apiDocsRoot, `${report.slug}.md`),
      `---
title: ${yamlString(`${report.packageName} API`)}
description: ${yamlString(`Public declaration report for ${report.packageName}.`)}
---
${generatedNotice}

${source}
`,
    );
  }
}

function generateExamplesPage(exampleItems) {
  const rows = exampleItems
    .map(
      (example) =>
        `| [${example.title}](${sourceDirectoryLink(example.dir)}) | ${example.description} | ${formatList(example.dependencies)} | ${formatList(example.scripts)} |`,
    )
    .join("\n");

  writeFileIfChanged(
    join(docsRoot, "examples.md"),
    `---
title: ${yamlString("Examples")}
description: ${yamlString("Generated index of runnable LoggerJS examples.")}
---
${generatedNotice}

# Examples

Runnable examples live in the repository under \`examples/\`. Build the packages first when an example imports local \`dist\` output directly.

| Example | What it shows | Dependencies | Scripts |
| --- | --- | --- | --- |
${rows}

## Local Workflow

\`\`\`bash
pnpm install
pnpm build
pnpm --filter loggerjs-node-basic-example start
pnpm --filter loggerjs-browser-basic-example dev
node examples/pretty-output/node.mjs
\`\`\`
`,
  );
}

const packages = packageMetadata();
const reports = apiReports();
const exampleItems = examples();

generateReferenceIndex();
generatePackagesPage(packages);
generateApiPages(reports);
generateExamplesPage(exampleItems);

console.log(
  `Generated ${relative(repoRoot, referenceRoot)} and ${relative(repoRoot, join(docsRoot, "examples.md"))}.`,
);
